Here's a solid pattern using `MockHttpMessageHandler` and MSTest's async support:

```csharp
[TestClass]
public class DataFetcherTests
{
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsHttpRequestException_On500()
    {
        var handler = new MockHandler(new HttpResponseMessage(HttpStatusCode.InternalServerError));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_HonoursCancellationToken()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        var handler = new MockHandler(new HttpResponseMessage(HttpStatusCode.OK));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)] // MSTest-level safety net (milliseconds)
    public async Task FetchAsync_SlowServer_TimesOutViaCancellation()
    {
        var handler = new MockHandler(async (_, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(10), ct); // simulate slow server
            return new HttpResponseMessage(HttpStatusCode.OK);
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(100));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Reusable mock handler
    private sealed class MockHandler : HttpMessageHandler
    {
        private readonly Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> _send;

        public MockHandler(HttpResponseMessage response)
            : this((_, _) => Task.FromResult(response)) { }

        public MockHandler(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> send)
            => _send = send;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return _send(request, cancellationToken);
        }
    }
}
```

**Key takeaways:**

- **Mock at `HttpMessageHandler`**, not `HttpClient` — this is the standard seam and avoids needing third-party mocking libraries.
- **Pre-cancelled tokens** (`cts.Cancel()`) verify the code checks cancellation eagerly.
- **`CancellationTokenSource(TimeSpan)`** tests realistic timeout behavior.
- **`[Timeout(3000)]`** is a safety net so a broken test doesn't hang your CI — it kills the test if it exceeds 3 seconds. Keep it generous; the actual assertion should fire much faster.
- Always use `async Task` (not `async void`) for test methods so MSTest properly awaits and reports exceptions.
